// src/assets.js
var BG = "data:image/png;base64,";
var LOGO = "data:image/png;base64,";

// src/format.js
function fmtSf(n) {
  if (n == null) return "\u2014";
  const num = Number(n);
  if (isNaN(num)) return "\u2014";
  if (Math.abs(num) >= 1e9) return (num / 1e9).toFixed(1) + "B";
  if (Math.abs(num) >= 1e6) return (num / 1e6).toFixed(1) + "M";
  if (Math.abs(num) >= 1e3) return (num / 1e3).toFixed(0) + "K";
  return num.toLocaleString();
}
function fmtDate(d) {
  if (!d) return "\u2014";
  if (typeof d === "string") {
    const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(d);
    if (m) {
      const dt = new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));
      return dt.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
    }
  }
  return new Date(d).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
}

// src/csdeck.js
var sumSf = (rows) => rows.reduce((a, b) => a + (Number(b.total_sf) || 0), 0);
var sumAvail = (rows) => rows.reduce((a, b) => a + (Number(b.sf_available) || 0), 0);
var rateStr = (n) => n != null && Number.isFinite(Number(n)) ? "$" + Number(n).toFixed(2) : "\u2014";
var STATUS_RANK = { "Existing": 0, "Under Construction": 1, "Proposed": 2 };
var statusRank = (s) => STATUS_RANK[s] ?? 3;
var commTime = (c) => {
  const t = c?.comm_date ? new Date(c.comm_date).getTime() : NaN;
  return Number.isFinite(t) ? t : -Infinity;
};
var DELIVERY_RE = /^(estimated\s+)?(q[1-4]\s*)?\d{4}$/i;
var stripEst = (s) => String(s).replace(/^estimated\s+/i, "").trim();
function deliveryStr(b) {
  const qd = String(b.quarter_delivered || "").trim();
  if (qd) return stripEst(qd);
  const vt = String(b.vacancy_type || "").trim();
  if (vt && DELIVERY_RE.test(vt)) return stripEst(vt);
  return null;
}
function genOrDelivery(b) {
  if (b.status === "Existing") {
    const avail = Number(b.sf_available) || 0;
    return avail > 0 && (b.vacancy_type === "1st GEN" || b.vacancy_type === "2nd GEN") ? b.vacancy_type : "\u2014";
  }
  const d = deliveryStr(b);
  return d ? `${d} (exp.)` : "\u2014";
}
var SUPPLY_HEAD = ["Building", "Submarket", "Total SF", "Available", "Gen", "Status", "Asking $/SF", "Owner"];
function supplyRow(cs, b, mark) {
  const rate = rateStr(cs.ratesByBuilding?.[b.id]?.rate);
  return [
    (mark ? "\u2605 " : "") + (b.building_name || b.address || "\u2014"),
    b.submarket || "\u2014",
    fmtSf(b.total_sf),
    (Number(b.sf_available) || 0) > 0 ? fmtSf(b.sf_available) : "\u2014",
    genOrDelivery(b),
    b.status || "\u2014",
    rate,
    b.owner || "\u2014"
  ];
}
function competitorsFor(cs, subject) {
  const map = cs.competitorsBySubject;
  if (map && Array.isArray(map[subject.id])) return map[subject.id];
  return cs.competitors || [];
}
var SUPPLY_COLW = [2.7, 1.3, 1, 1, 0.95, 1.3, 1.15, 2.83];
var COMPS_COLW = [2.8, 2.6, 3.2, 1.1, 1.1, 1.43];
var monthYear = () => (/* @__PURE__ */ new Date()).toLocaleDateString("en-US", { month: "long", year: "numeric" });
function csHeader(cs) {
  const market = cs.market || "Fort Worth";
  const scopeBits = [cs.submarket, cs.radiusMi != null ? `${cs.radiusMi} mi radius` : null, monthYear()].filter(Boolean);
  return { eyebrow: `${market} Industrial \u2014 Competitive Set`, meta: scopeBits.join(" \xB7 ") };
}
function subjectLabel(cs) {
  if (cs.projectName) return cs.projectName;
  if (cs.subjects?.length === 1) return cs.subjects[0].building_name || cs.subjects[0].address || "Subject";
  if (cs.subjects?.length > 1) return `${cs.subjects.length} Subject Buildings`;
  return "Subject";
}
var SUBJECT_KPIS = [
  { key: "cs-subjects", label: "Subject Buildings", value: (cs) => cs.subjects.length.toLocaleString() },
  { key: "cs-subject-sf", label: "Subject SF", value: (cs) => fmtSf(sumSf(cs.subjects)) },
  { key: "cs-subject-avail", label: "Subject Available SF", value: (cs) => fmtSf(sumAvail(cs.subjects)) },
  { key: "cs-competing", label: "Competing Buildings", value: (cs) => cs.competitors.length.toLocaleString() },
  { key: "cs-comps", label: "Comparable Comps", value: (cs) => cs.comps.length.toLocaleString() },
  { key: "cs-avg-rate", label: "Avg Comp Rate", value: (cs) => {
    const r = cs.comps.map((c) => Number(c.start_rate)).filter((x) => x > 0);
    return r.length ? "$" + (r.reduce((a, b) => a + b, 0) / r.length).toFixed(2) : "\u2014";
  } }
];
function subjectKpis(cs) {
  return SUBJECT_KPIS.map((k) => ({ label: k.label, value: k.value(cs) }));
}
function subjectSupplyTable(cs, subject) {
  const compRows = [...competitorsFor(cs, subject)].sort((a, b) => statusRank(a.status) - statusRank(b.status) || (Number(b.total_sf) || 0) - (Number(a.total_sf) || 0)).map((b) => supplyRow(cs, b, false));
  return { head: SUPPLY_HEAD, rows: [supplyRow(cs, subject, true), ...compRows] };
}
function competingSupplyTablesBySubject(cs) {
  return (cs.subjects || []).map((s) => ({
    subjectId: s.id,
    title: s.building_name || s.address || "Subject",
    ...subjectSupplyTable(cs, s)
  }));
}
function competingSupplyTable(cs) {
  const subjectRows = (cs.subjects || []).map((b) => supplyRow(cs, b, true));
  const compRows = [...cs.competitors || []].sort((a, b) => statusRank(a.status) - statusRank(b.status) || (Number(b.total_sf) || 0) - (Number(a.total_sf) || 0)).map((b) => supplyRow(cs, b, false));
  return { head: SUPPLY_HEAD, rows: [...subjectRows, ...compRows] };
}
function compsTable(cs) {
  const rows = [...cs.comps].sort((a, b) => commTime(b) - commTime(a)).map((c) => [
    c.tenant || "\u2014",
    c.owner || "\u2014",
    c.building_name || c.address || "\u2014",
    fmtSf(c.leased_sf),
    rateStr(c.start_rate),
    fmtDate(c.comm_date)
  ]);
  return { head: ["Tenant", "Landlord", "Building", "SF", "Rate", "Comm."], rows };
}

// src/pptx.js
var DECK_W = 13.333;
var DECK_H = 7.5;
var MARGIN = 0.55;
var NAVY = "1F2A4D";
var SLATE = "334155";
var MUTED = "64748B";
var FAINT = "94A3B8";
var CARD_BG = "F8FAFC";
var BORDER = "E2E8F0";
var WHITE = "FFFFFF";
var FONT = "Arial";
async function createDeck({ author = "HPI" } = {}) {
  const PptxGenJS = (await import("pptxgenjs")).default;
  const deck = new PptxGenJS();
  deck.defineLayout({ name: "HPI_WIDE", width: DECK_W, height: DECK_H });
  deck.layout = "HPI_WIDE";
  deck.author = author;
  deck.company = "HPI";
  deck._assets = { bg: BG, logo: LOGO };
  return deck;
}
function addCoverSlide(deck, { market = "FORT WORTH", title = "", date = "" }) {
  const s = deck.addSlide();
  s.background = { data: deck._assets.bg };
  const lines = [];
  if (market) lines.push({ text: market.toUpperCase(), options: { fontSize: 30, bold: true, color: WHITE, breakLine: true } });
  if (title) lines.push({ text: title.toUpperCase(), options: { fontSize: 26, bold: true, color: WHITE, breakLine: true } });
  if (date) lines.push({ text: date.toUpperCase(), options: { fontSize: 22, bold: true, color: WHITE, breakLine: true } });
  s.addText(lines, { x: 1, y: 2.5, w: DECK_W - 2, h: 2.5, align: "center", valign: "middle", fontFace: FONT });
  s.addImage({ data: deck._assets.logo, x: DECK_W - 2.7, y: DECK_H - 1.3, w: 1.95, h: 0.85, sizing: { type: "contain", w: 1.95, h: 0.85 } });
  return s;
}
function addBackSlide(deck) {
  const s = deck.addSlide();
  s.background = { data: deck._assets.bg };
  const w = 3.4, h = 1.5;
  s.addImage({ data: deck._assets.logo, x: (DECK_W - w) / 2, y: (DECK_H - h) / 2, w, h, sizing: { type: "contain", w, h } });
  return s;
}
function addContentSlide(deck, title, { eyebrow, meta } = {}) {
  const s = deck.addSlide();
  s.background = { color: WHITE };
  let top = MARGIN;
  if (eyebrow) {
    s.addText(String(eyebrow).toUpperCase(), { x: MARGIN, y: top, w: DECK_W - 2 * MARGIN, h: 0.22, fontSize: 9, bold: true, color: MUTED, charSpacing: 1, fontFace: FONT });
    top += 0.28;
  }
  if (title) {
    const metaW = 6.2;
    s.addText(title, { x: MARGIN, y: top, w: DECK_W - 2 * MARGIN - (meta ? metaW : 0), h: 0.5, fontSize: 18, bold: true, color: NAVY, fontFace: FONT });
    if (meta) {
      s.addText(String(meta), { x: DECK_W - MARGIN - metaW, y: top + 0.04, w: metaW, h: 0.42, fontSize: 9.5, italic: true, color: FAINT, align: "right", valign: "middle", wrap: false, fit: "shrink", fontFace: FONT });
    }
    top += 0.52;
    s.addText("", { x: MARGIN, y: top, w: DECK_W - 2 * MARGIN, h: 0.014, fill: { color: BORDER }, line: { type: "none" }, margin: 0 });
    top += 0.16;
  }
  return { slide: s, top };
}
function addKpiStrip(slide, kpis, { x = MARGIN, y, w = DECK_W - 2 * MARGIN, h = 0.95, gap = 0.15 } = {}) {
  const n = kpis.length || 1;
  const cardW = (w - gap * (n - 1)) / n;
  kpis.forEach((k, i) => {
    const cx = x + i * (cardW + gap);
    slide.addText([
      { text: String(k.label || "").toUpperCase(), options: { fontSize: 8, color: MUTED, bold: true, breakLine: true } },
      { text: String(k.value ?? "\u2014"), options: { fontSize: 17, color: SLATE, bold: true, breakLine: true } },
      ...k.sub ? [{ text: String(k.sub), options: { fontSize: 8, color: FAINT } }] : []
    ], {
      shape: "roundRect",
      rectRadius: 0.06,
      x: cx,
      y,
      w: cardW,
      h,
      fill: { color: CARD_BG },
      line: { color: BORDER, width: 0.75 },
      align: "left",
      valign: "top",
      fontFace: FONT,
      lineSpacingMultiple: 1,
      margin: [6, 9, 6, 9]
    });
  });
  return y + h;
}
function addChartGrid(slide, images, { x = MARGIN, y, w = DECK_W - 2 * MARGIN, h, perRow = 2, gap = 0.25, bakedTitle = false } = {}) {
  if (!images.length) return y;
  const rows = Math.ceil(images.length / perRow);
  const cellW = (w - gap * (perRow - 1)) / perRow;
  const cellH = (h - gap * (rows - 1)) / rows;
  images.forEach((img, i) => {
    const r = Math.floor(i / perRow), c = i % perRow;
    const cx = x + c * (cellW + gap);
    const cy = y + r * (cellH + gap);
    let labelH = 0;
    if (img.label && !bakedTitle) {
      slide.addText(String(img.label).toUpperCase(), { x: cx, y: cy, w: cellW, h: 0.3, fontSize: 9, bold: true, color: MUTED, fontFace: FONT });
      labelH = 0.34;
    }
    slide.addImage({ data: img.png, x: cx, y: cy + labelH, w: cellW, h: cellH - labelH, sizing: { type: "contain", w: cellW, h: cellH - labelH } });
  });
  return y + h;
}
function addTable(slide, head, rows, { x = MARGIN, y, w = DECK_W - 2 * MARGIN, fontSize = 9, colW } = {}) {
  const body = [
    head.map((h) => ({ text: h, options: { bold: true, color: WHITE, fill: { color: NAVY }, fontSize: fontSize - 1 } })),
    ...rows.map((r) => r.map((c) => ({ text: String(c ?? ""), options: { color: SLATE, fontSize } })))
  ];
  slide.addTable(body, { x, y, w, colW, fontFace: FONT, border: { type: "solid", color: BORDER, pt: 0.5 }, autoPage: true, autoPageRepeatHeader: true, valign: "middle", rowH: 0.3 });
}
function addPaginatedTableSlides(deck, title, head, rows, { w = DECK_W - 2 * MARGIN, fontSize = 9, colW, bottomMargin = 0.45, header } = {}) {
  const top = MARGIN + (header?.eyebrow ? 0.96 : 0.68);
  const usableH = DECK_H - top - bottomMargin;
  const widths = colW || head.map(() => w / head.length);
  const lineH = fontSize / 72 * 1.25;
  const charW = fontSize * 92e-4;
  const rowHeight = (cells) => {
    let lines = 1;
    cells.forEach((c, i) => {
      const cpl = Math.max(4, Math.floor((widths[i] || 1) / charW));
      lines = Math.max(lines, Math.ceil(String(c ?? "").length / cpl));
    });
    return Math.max(0.3, lines * lineH + 0.12);
  };
  const headerH = rowHeight(head) + 0.04;
  const pages = [];
  let cur = [], curH = headerH;
  for (const r of rows) {
    const rh = rowHeight(r);
    if (cur.length && curH + rh > usableH) {
      pages.push(cur);
      cur = [];
      curH = headerH;
    }
    cur.push(r);
    curH += rh;
  }
  if (cur.length) pages.push(cur);
  pages.forEach((chunk, i) => {
    const s = addContentSlide(deck, i === 0 ? title : `${title} (continued)`, header);
    addTable(s.slide, head, chunk, { y: s.top, w, fontSize, colW: widths });
  });
  return pages.length;
}
async function downloadDeck(deck, filename) {
  await deck.writeFile({ fileName: filename.endsWith(".pptx") ? filename : `${filename}.pptx` });
}
function addCompetitiveSetSlides(deck, cs) {
  const subj = subjectLabel(cs);
  const header = csHeader(cs);
  const k = addContentSlide(deck, `Competitive Set \u2014 ${subj}`, header);
  addKpiStrip(k.slide, subjectKpis(cs), { y: k.top });
  for (const t of competingSupplyTablesBySubject(cs)) {
    if (t.rows.length) {
      addPaginatedTableSlides(deck, `Competing Supply \u2014 ${t.title}`, t.head, t.rows, { colW: SUPPLY_COLW, header });
    }
  }
  const comps = compsTable(cs);
  if (comps.rows.length) {
    addPaginatedTableSlides(deck, `Comparable Lease Comps \u2014 ${subj}`, comps.head, comps.rows, { colW: COMPS_COLW, header });
  }
}
export {
  COMPS_COLW,
  DECK_H,
  DECK_W,
  SUBJECT_KPIS,
  SUPPLY_COLW,
  SUPPLY_HEAD,
  addBackSlide,
  addChartGrid,
  addCompetitiveSetSlides,
  addContentSlide,
  addCoverSlide,
  addKpiStrip,
  addPaginatedTableSlides,
  addTable,
  competingSupplyTable,
  competingSupplyTablesBySubject,
  compsTable,
  createDeck,
  csHeader,
  downloadDeck,
  subjectKpis,
  subjectLabel,
  subjectSupplyTable
};
